```csharp
using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(int count = 1) =>
        Enumerable.Range(1, count)
            .Select(i => new OrderItem { ProductName = $"Item{i}", Price = 10m * i, Quantity = i })
            .ToList();

    [TestMethod]
    public void CreateOrder_WithValidInput_ReturnsOrderWithCorrectTotal()
    {
        // Arrange
        var items = new List<OrderItem>
        {
            new() { ProductName = "Widget", Price = 25.00m, Quantity = 2 },
            new() { ProductName = "Gadget", Price = 10.00m, Quantity = 3 },
        };

        // Act
        var order = _service.CreateOrder("cust-1", items);

        // Assert
        Assert.AreEqual("cust-1", order.CustomerId);
        Assert.AreEqual(80.00m, order.Total); // 25*2 + 10*3
        Assert.IsNotNull(order.Id);
        Assert.HasCount(2, order.Items);
    }

    [TestMethod]
    public void CreateOrder_WithNullCustomerId_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder(null!, CreateItems()));

        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithNullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(
            () => _service.CreateOrder("cust-1", null!));

        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_WithEmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));

        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    [TestMethod]
    public void GetOrder_WithExistingId_ReturnsOrder()
    {
        // Arrange
        var created = _service.CreateOrder("cust-1", CreateItems());

        // Act
        var found = _service.GetOrder(created.Id);

        // Assert
        Assert.AreSame(created, found);
    }

    [TestMethod]
    public void GetOrder_WithNonExistentId_ReturnsNull()
    {
        Assert.IsNull(_service.GetOrder("does-not-exist"));
    }

    [TestMethod]
    public void GetOrdersByCustomer_ReturnsOnlyMatchingOrders()
    {
        // Arrange
        _service.CreateOrder("cust-A", CreateItems());
        _service.CreateOrder("cust-A", CreateItems(2));
        _service.CreateOrder("cust-B", CreateItems());

        // Act
        var results = _service.GetOrdersByCustomer("cust-A");

        // Assert
        Assert.HasCount(2, results);
    }

    [TestMethod]
    public void GetOrdersByCustomer_WithNoOrders_ReturnsEmptyList()
    {
        var results = _service.GetOrdersByCustomer("nobody");

        Assert.IsEmpty(results);
    }

    [TestMethod]
    [DataRow(1, 5, 5.00)]
    [DataRow(3, 2, 6.00)]
    [DataRow(1, 1, 1.00)]
    public void CreateOrder_CalculatesTotalCorrectly(int quantity, double price, double expectedTotal)
    {
        var items = new List<OrderItem>
        {
            new() { ProductName = "Test", Price = (decimal)price, Quantity = quantity }
        };

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual((decimal)expectedTotal, order.Total);
    }
}
```

**Key patterns demonstrated:**

- **`sealed` test class** — better performance, clearer design intent
- **`Assert.ThrowsExactly<T>`** — matches only the exact exception type (not derived)
- **Constructor initialization** — enables `readonly` fields
- **`Assert.HasCount` / `Assert.IsEmpty`** — specific collection assertions with clear failure messages
- **`Assert.AreSame`** — reference equality for verifying the same instance is returned
- **`[DataRow]`** — parameterized tests for calculation logic
- **AAA pattern** with `MethodName_Scenario_ExpectedBehavior` naming

For the project file, use `MSTest.Sdk` for the simplest setup:

```xml
